#include <bits/stdc++.h>
using namespace std;

int ix, iy, ia, ib;
long long x, y, a, b;

int main() {
	cin>>x>>y>>a>>b;
	ix = x;
	iy = y;
	ia = a;
	ib = b;
	if (x * a != ix * ia || x * b != ix * ib || y * a != iy * ia || y * b != iy * ib) printf("long long int\n");
	else cout<<"int\n";
	return 0;
}
